import{_ as a,o as e,c as r,a2 as o}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"查理·芒格","description":"","frontmatter":{"title":"查理·芒格"},"headers":[],"relativePath":"04_people/查理·芒格.md","filePath":"04_people/查理·芒格.md"}'),l={name:"04_people/查理·芒格.md"};function d(i,t,n,h,s,u){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="查理·芒格-charlie-munger" tabindex="-1">查理·芒格（Charlie Munger） <a class="header-anchor" href="#查理·芒格-charlie-munger" aria-label="Permalink to &quot;查理·芒格（Charlie Munger）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>姓名</strong></td><td>Charles T. Munger（查理·芒格）</td></tr><tr><td><strong>出生</strong></td><td>1924年</td></tr><tr><td><strong>逝世</strong></td><td>2023年（99岁）</td></tr><tr><td><strong>职位</strong></td><td>伯克希尔·哈撒韦副董事长</td></tr><tr><td><strong>关联公司</strong></td><td>伯克希尔·哈撒韦</td></tr><tr><td><strong>首次提及</strong></td><td>1978年</td></tr></tbody></table><h2 id="与巴菲特的故事" tabindex="-1">与巴菲特的故事 <a class="header-anchor" href="#与巴菲特的故事" aria-label="Permalink to &quot;与巴菲特的故事&quot;">​</a></h2><p>查理·芒格是巴菲特的核心搭档和终身合伙人。两人最初通过共同的朋友介绍认识，后于1978年通过蓝筹印花公司与伯克希尔的合并正式成为搭档。</p><h3 id="合伙关系" tabindex="-1">合伙关系 <a class="header-anchor" href="#合伙关系" aria-label="Permalink to &quot;合伙关系&quot;">​</a></h3><p>巴菲特多次在股东信中强调芒格对自己的影响：</p><blockquote><p>&quot;查理·芒格和我在做管理合伙人工作，管理伯克希尔的所有控股企业。这工作我们享受得几乎罪过。&quot;（1983年股东信）</p></blockquote><blockquote><p>&quot;我们之间的商业决策可以互换——打个电话比开半天委员会会议更有效。&quot;（1983年股东信）</p></blockquote><blockquote><p>&quot;查理和我共同负责两件事：吸引和留住优秀经理人，配置资本。&quot;（1987年股东信）</p></blockquote><h3 id="思想影响" tabindex="-1">思想影响 <a class="header-anchor" href="#思想影响" aria-label="Permalink to &quot;思想影响&quot;">​</a></h3><p>芒格深刻改变了巴菲特的投资哲学：</p><ol><li><strong>从&quot;便宜买差企业&quot;到&quot;合理价买好企业&quot;</strong> — 芒格说服巴菲特转变投资框架</li><li><strong>研究失败比研究成功更重要</strong>（1984年股东信）</li><li><strong>多元思维模型</strong>（lollapalooza effect）</li><li><strong>避免做蠢事</strong>胜过努力做聪明事</li></ol><h3 id="具体贡献" tabindex="-1">具体贡献 <a class="header-anchor" href="#具体贡献" aria-label="Permalink to &quot;具体贡献&quot;">​</a></h3><ul><li>建议买入喜诗糖果（1972年） — 被认为是巴菲特投资理念转变的关键案例</li><li>帮助韦斯考金融重新定位（1970年代）</li><li>推动1983年蓝筹印花与伯克希尔合并</li><li>提出&quot;股东指定捐赠项目&quot;（1981年）</li></ul><h3 id="与巴菲特互补" tabindex="-1">与巴菲特互补 <a class="header-anchor" href="#与巴菲特互补" aria-label="Permalink to &quot;与巴菲特互补&quot;">​</a></h3><table tabindex="0"><thead><tr><th>巴菲特</th><th>芒格</th></tr></thead><tbody><tr><td>更乐观</td><td>更理性批判</td></tr><tr><td>数字导向</td><td>定性分析强</td></tr><tr><td>公众形象</td><td>幕后思考</td></tr></tbody></table><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>1977, 1978, 1979, 1980, 1981, 1982, 1983, 1984, 1985, 1986, 1987, 1988, 1989, 1990, 1991, 1992, 1993, 1994, 1995, 1996, 1997, 1998, 1999</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/伯克希尔哈撒韦.html">伯克希尔·哈撒韦</a> - 服务的企业</li><li><a href="./沃伦·巴菲特.html">沃伦·巴菲特</a> - 搭档</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',23)])])}const b=a(l,[["render",d]]);export{q as __pageData,b as default};
